import React, { useState } from "react";
import { TextField, Button, Box, Typography } from "@mui/material";
import axios from "axios";

function AddFirm() {
  const [firm, setFirm] = useState({
    name: "",
    class: "",
    address: "",
    sicilNo: "",
    phone: "",
    email: "",
    manager: "",
    isgExpert: "",
    doctor: ""
  });

  const saveFirm = async () => {
    const res = await axios.post("/firms", firm);
    alert("Firma kaydedildi!");
    // yönlendirme için react-router navigate kullanılabilir
  };

  return (
    <Box p={2}>
      <Typography variant="h6">Yeni Firma Ekle</Typography>
      <TextField label="Firma Adı" fullWidth value={firm.name}
        onChange={e => setFirm({...firm, name: e.target.value})} />
      <TextField label="Tehlike Sınıfı" fullWidth value={firm.class}
        onChange={e => setFirm({...firm, class: e.target.value})} />
      <TextField label="Adres" fullWidth value={firm.address}
        onChange={e => setFirm({...firm, address: e.target.value})} />
      <TextField label="Sicil No" fullWidth value={firm.sicilNo}
        onChange={e => setFirm({...firm, sicilNo: e.target.value})} />
      <TextField label="Telefon No" fullWidth value={firm.phone}
        onChange={e => setFirm({...firm, phone: e.target.value})} />
      <TextField label="Email" fullWidth value={firm.email}
        onChange={e => setFirm({...firm, email: e.target.value})} />
      <TextField label="Yetkili Ad Soyad / Ünvan" fullWidth value={firm.manager}
        onChange={e => setFirm({...firm, manager: e.target.value})} />
      <TextField label="Yetkili İSG Uzmanı" fullWidth value={firm.isgExpert}
        onChange={e => setFirm({...firm, isgExpert: e.target.value})} />
      <TextField label="Yetkili İşyeri Hekimi" fullWidth value={firm.doctor}
        onChange={e => setFirm({...firm, doctor: e.target.value})} />

      <Button variant="contained" sx={{ mt: 2 }} onClick={saveFirm}>Kaydet</Button>
    </Box>
  );
}

export default AddFirm;
